UPDATE produits_complementaires SET phrase_conseil = sub.phrase FROM (VALUES ('0bc22b72-608b-4b74-be6d-ff910c166035'::uuid, 'La conjonctivite allergique provoque une inflammation oculaire, ce collyre réduit le prurit et le larmoiement.'), ('372f146e-14ec-47ba-9d11-85d7990dd919'::uuid, 'La conjonctivite allergique entraîne irritation et gonflement, ces compresses aident à apaiser les paupières enflammées.'), ('8c2903ab-a76c-48f0-b158-a48542c2f9fe'::uuid, 'La conjonctivite allergique est due à des irritants, le sérum physiologique aide à rincer l''œil et éliminer les allergènes.'), ('38e4e8cb-2371-42a9-bcf5-0040f80d81f7'::uuid, 'Pour la conjonctivite bactérienne, le sérum physiologique aide à nettoyer l''œil et éliminer les sécrétions avant traitement.'), ('aeb2d7c8-a58c-4e59-a0c4-739729e658fe'::uuid, 'Pour la conjonctivite bactérienne, des compresses stériles sont essentielles pour nettoyer les yeux et maintenir l''hygiène.'), ('a6a29862-6580-4851-a8cb-f4e35ffa2826'::uuid, 'Pour la conjonctivite bactérienne, les compresses stériles aident à nettoyer l''œil sans risque de contamination additionnelle.'), ('e6153553-e057-44ac-9b96-1cfb92a3e03c'::uuid, 'La constipation résulte d''un ralentissement du transit, ce laxatif osmotique augmente l''eau dans l''intestin et ramollit les selles.'), ('843b8b73-a875-4692-af3a-8c6497d30ac9'::uuid, 'Le psyllium aide à ramollir les selles et augmenter leur volume pour faciliter le transit intestinal et réduire la constipation.'), ('0508741a-fbc9-4edf-8893-8d68e39a0e42'::uuid, 'La constipation est souvent due à un manque de fibres, le psyllium blond augmente le volume des selles et stimule le transit.'), ('ff6715fd-d90d-4668-8c48-4edb3b52ebf2'::uuid, 'La constipation occasionnelle ralentit le transit, ce laxatif osmotique aide à augmenter l''hydratation des selles pour les expulser.'), ('db1650eb-cd41-41d4-a0d8-40828708558e'::uuid, 'La constipation est souvent liée à un apport insuffisant en fibres, ce complément aide à régulariser le transit intestinal.'), ('c5ed4515-730a-4e09-b5f1-bcf67236fd77'::uuid, 'La constipation est parfois due à un déséquilibre de la flore intestinale, ces probiotiques aident à normaliser le transit.'), ('70276889-c8c0-4f19-9da2-7d160a6796ab'::uuid, 'Certains contraceptifs peuvent affecter le métabolisme osseux, la vitamine D3 aide à maintenir une bonne densité osseuse.'), ('65f24f43-b315-428b-bb78-e533334d118f'::uuid, 'La contraception hormonale peut influencer les réserves, la vitamine D3 aide à soutenir la santé osseuse et immunitaire.'), ('d6ca28a5-173d-45e7-9edf-74e3f4ba6f61'::uuid, 'Pour éviter les oublis de pilule, le pilulier aide à assurer une prise régulière et optimiser l''efficacité contraceptive.'), ('d911d2b5-29c8-415a-a413-a3f124c1fec7'::uuid, 'Après une contusion, la vitamine D3 aide à favoriser la réparation tissulaire et renforcer l''intégrité osseuse si impactée.'), ('a386aa8a-596e-47bb-845e-5bf218015886'::uuid, 'Après une contusion ou ecchymose, la vitamine D3 aide la consolidation osseuse et module la réponse inflammatoire locale.'), ('81982190-f31d-4006-a7f9-29cf38e4eda8'::uuid, 'Après une contusion, la vitamine D3 aide à soutenir la résistance osseuse et moduler la réponse inflammatoire des tissus.'), ('080d680f-0db5-4fca-a8a9-76a42d2619e6'::uuid, 'La convalescence épuise les réserves nutritionnelles, les multivitamines apportent les micronutriments essentiels pour une récupération complète.'), ('128bd48c-03e4-4f00-980f-63eeac993cc0'::uuid, 'Après un stress physiologique, les tissus nécessitent une réparation, les protéines enrichies facilitent la reconstruction cellulaire des muscles et organes.'), ('777170bb-fb08-43a6-bb58-0ef79f71e69a'::uuid, 'Une convalescence peut générer des carences, un multivitamines complet réapprovisionne l''organisme en nutriments fondamentaux pour l''énergie vitale.'), ('751806ad-4b11-423c-943a-cf72eb276265'::uuid, 'Un coup de soleil endommage la barrière cutanée et déshydrate la peau, un après-soleil apaise et aide à restaurer l''intégrité épidermique.'), ('ee32e07f-eb7f-4787-9a7d-695757ffb2fa'::uuid, 'La peau brûlée par le soleil présente une inflammation locale, la Biafine aide à calmer l''échauffement et favorise la cicatrisation cutanée.'), ('ba327963-be24-4ee7-b0dd-1fdcb3b55b36'::uuid, 'L''exposition solaire excessive provoque des dommages cellulaires, la crème solaire SPF50+ filtre les UV pour prévenir les brûlures et le vieillissement prématuré.'), ('44e0e94b-a686-4194-955e-3e1e35c0f81a'::uuid, 'Les crampes abdominales sont souvent dues à des contractions musculaires involontaires, le phloroglucinol agit sur le spasme pour soulager la douleur rapidement.'), ('b461c5b3-f113-45e2-ae3f-d36247c83492'::uuid, 'Les crampes abdominales résultent d''une tension musculaire excessive, la chaleur de la bouillotte aide à décontracter les muscles lisses du ventre.'), ('15371e51-0958-41d5-835e-86941e3e2021'::uuid, 'Des crampes abdominales surviennent souvent lors de spasmes intestinaux, cette tisane détend les muscles lisses digestifs pour apaiser la douleur.'), ('3d1ea595-9956-41e6-80ee-dbc1fb8647ea'::uuid, 'Une carence en magnésium peut perturber l''équilibre électrolytique, ce complément soutient la fonction musculaire normale et réduit les crampes.'), ('d7d435fc-7fbf-4147-bbac-0aaed770d9cd'::uuid, 'Le manque de magnésium peut augmenter l''excitabilité neuromusculaire, le magnésium marin régule la contraction musculaire pour éviter les crampes.'), ('7892d3a1-36ea-4885-b100-490453f44eea'::uuid, 'Un déséquilibre électrolytique, comme une carence en potassium, peut provoquer des crampes, ce complément rétablit l''équilibre minéral essentiel.'), ('cb526459-b688-45a8-9527-4779c7d6579c'::uuid, 'La cystite est due à l''adhésion de bactéries aux voies urinaires, le cranberry concentré bloque cette fixation pour prévenir l''infection.'), ('507dc60c-5e41-40b8-84ed-6a1c50033fca'::uuid, 'Les infections urinaires sont causées par la fixation bactérienne, le cranberry empêche les bactéries pathogènes d''adhérer aux parois de la vessie.'), ('3b60698a-5598-4ceb-949f-2a3d7c0f9bd4'::uuid, 'Les bactéries urinaires se fixent sur la muqueuse vésicale, le D-Mannose empêche leur adhésion et facilite leur élimination naturelle.'), ('b8b5a3b4-40a6-4ae0-8c04-ae6615f14eb9'::uuid, 'Les bactéries adhérant aux voies urinaires causent la cystite, le cranberry concentré réduit leur fixation pour diminuer le risque d''infection.'), ('6ba4be00-f8ae-451f-a9c5-15e4f4f166fe'::uuid, 'La cystite est une infection bactérienne de la vessie, le D-Mannose empêche l''adhésion des bactéries pathogènes aux parois urinaires.'), ('8f1c5a24-f8c1-44eb-a6f2-88ecb9ab0c27'::uuid, 'Un pH vaginal déséquilibré peut favoriser les infections urinaires, ce gel aide à maintenir l''acidité naturelle pour protéger la flore intime.'), ('30f40ce0-2e60-4866-83b7-095fec723133'::uuid, 'Les cystites récidivantes sont souvent liées à l''adhésion bactérienne, les gélules de canneberge réduisent la fixation des bactéries aux voies urinaires.'), ('9129b697-98d6-4005-9aca-582d2a6ed2bb'::uuid, 'Les infections urinaires récurrentes sont dues à la fixation bactérienne, le D-Mannose en poudre gêne l''adhésion des bactéries à la vessie.'), ('15a0ffc6-9b45-498f-816e-7d4063ee4279'::uuid, 'Le déséquilibre de la flore vaginale peut favoriser les cystites, les probiotiques rétablissent l''équilibre microbien pour prévenir les récidives.'), ('c5dc11aa-5b6d-4108-b043-05de34944694'::uuid, 'Le décalage horaire perturbe le rythme circadien naturel, la mélatonine aide à resynchroniser l''horloge biologique et facilite l''endormissement.'), ('447f07af-72de-4765-9506-5cc1824fbf37'::uuid, 'Le décalage horaire désoriente le cycle veille-sommeil, la mélatonine 1,9mg aide à recalibrer le rythme circadien pour un meilleur sommeil.'), ('31d9e2b1-32ba-4557-85f3-2cccdaff0ea7'::uuid, 'La lumière perturbe la production de mélatonine et l''endormissement, le masque de sommeil crée l''obscurité nécessaire pour favoriser un sommeil réparateur.'), ('d5627ed3-b679-4776-ab63-d78e86a5497a'::uuid, 'Le stress et la fatigue nerveuse peuvent affecter l''humeur, le magnésium marin B6 soutient le fonctionnement du système nerveux et réduit l''irritabilité.'), ('92ddc100-9b76-42af-ad88-89a2413db88d'::uuid, 'Une carence en vitamine D est souvent associée à une humeur altérée, ce supplément aide à réguler les processus neuronaux impliqués dans la dépression.'), ('3e6dd947-1676-4afd-a566-617f81dadfd6'::uuid, 'La dépression implique des déséquilibres de neurotransmetteurs, le safran agit sur la sérotonine pour améliorer l''humeur et réduire l''anxiété.'), ('e8476102-9b61-43ca-a403-7cc53d8b1496'::uuid, 'La dermatite de contact perturbe la barrière cutanée et provoque une sécheresse, cette crème émolliente aide à réparer et hydrater la peau.'), ('4f6e0881-703a-42ab-aabc-3148a7f4310b'::uuid, 'La dermatite de contact provoque une inflammation et des rougeurs, l''hydrocortisone diminue l''inflammation pour apaiser les démangeaisons cutanées.'), ('94e47846-f33d-47cb-b6b1-701812862aaf'::uuid, 'La peau atteinte de dermatite est fragilisée et réagit aux irritants, ce syndet sans savon nettoie en douceur sans agresser la barrière cutanée.'), ('90736e9e-ea6a-4e68-a141-a0c8a302be0a'::uuid, 'La déshydratation entraîne une perte d''eau et d''électrolytes, les SRO compensent ces pertes pour restaurer l''équilibre hydrique du corps.'), ('e83a25c0-d244-40a6-8bd4-fd8d366306a6'::uuid, 'Une forte perte de liquides corporels mène à la déshydratation, les sachets SRO apportent eau et sels minéraux pour rétablir l''hydratation.') ) AS sub(id, phrase) WHERE produits_complementaires.id = sub.id;
UPDATE produits_complementaires SET phrase_conseil = sub.phrase FROM (VALUES ('adb9c636-eb3a-43db-9e7a-52993ba78734'::uuid, 'La déshydratation réduit le volume sanguin et les minéraux essentiels, l''eau enrichie en minéraux aide à rééquilibrer le corps.'), ('1864b61e-0a8e-4127-9321-295e6db88c33'::uuid, 'Le foie est surchargé par les toxines endogènes et exogènes, le Desmodium soutient sa fonction détoxifiante pour le purifier.'), ('1cd90512-b9f6-41a6-9e59-47b31341395c'::uuid, 'La surcharge toxique peut affaiblir le foie, le Desmodium le protège en favorisant l''élimination des substances indésirables.'), ('792d3acb-30f8-47e5-9ba1-664a58399eb3'::uuid, 'Le foie est l''organe clé de la détoxification, le Chardon-Marie, grâce à la silymarine, protège et régénère les cellules hépatiques.'), ('cb482dcb-6cbf-4e22-a8d9-35470a2c4a79'::uuid, 'Le diabète insipide entraîne une polyurie et une déperdition d''électrolytes, les multivitamines compensent les carences induites par la perte urinaire.'), ('1fb928b6-0a4b-484c-be09-80975af1250c'::uuid, 'Le diabète insipide provoque une élimination excessive de minéraux, le magnésium + B6 aide à maintenir l''équilibre électrolytique perturbé.'), ('56f63bea-5b54-441a-b25e-d3d9439fc3e0'::uuid, 'Le diabète insipide peut affecter l''équilibre hydrique, les probiotiques soutiennent la flore intestinale pour une meilleure absorption des nutriments.'), ('1f922d97-144b-41c1-84fe-f0ae5aaa85a1'::uuid, 'Le diabète type 1 nécessite un contrôle glycémique strict et constant, les bandelettes permettent de mesurer précisément le taux de sucre sanguin.'), ('1cbe5a0b-daf1-4573-b6c8-ccff0e6dfde8'::uuid, 'Le diabète peut perturber l''équilibre vitaminique, ce soutien multi-vitaminique aide à compenser les carences.'), ('cee0acd4-b97f-476b-b16e-8403b8fe78c0'::uuid, 'Pour les injections d''insuline, ces aiguilles fines minimisent la douleur et l''irritation cutanée lors de la piqûre.'), ('b41c71f7-918b-439b-b7ed-a4b406e91579'::uuid, 'La surveillance glycémique est cruciale dans le diabète de type 2, ce lecteur permet un suivi précis de votre glycémie.'), ('7fcc6287-db22-426f-b09e-2be7a701908c'::uuid, 'Pour un suivi glycémique régulier, ces bandelettes réactives sont essentielles pour mesurer précisément votre taux de sucre.'), ('7c2922a1-05aa-4c92-bc88-e4923aedb05d'::uuid, 'Le diabète de type 2 peut affecter l''absorption des nutriments, ce complément aide à maintenir un équilibre vitaminique.'), ('32fe0b73-b526-4515-947f-92b0db7991c3'::uuid, 'La diarrhée entraîne une perte hydrique et électrolytique, ces sachets aident à compenser et prévenir la déshydratation.'), ('9d6c952c-55ec-4920-80d1-2c8bf3509a61'::uuid, 'Les épisodes de diarrhée causent une perte d''eau et de sels minéraux, cette solution aide à restaurer l''équilibre hydro-électrolytique.'), ('c7511bea-5363-4fab-a07f-01b39b391ff5'::uuid, 'La diarrhée perturbe l''équilibre du microbiote intestinal, ces probiotiques multi-souches aident à restaurer la flore digestive.'), ('f66b47fa-3181-4b89-897a-168687da7c60'::uuid, 'La diarrhée simple provoque une perte de liquides et d''électrolytes, cette solution aide à réhydrater rapidement l''organisme.'), ('63b8f389-0f8c-43e4-be07-0aba7ebeb218'::uuid, 'La diarrhée déséquilibre le microbiote intestinal, ces probiotiques aident à restaurer une flore saine.'), ('eac14bd2-0d88-433f-851c-bb6cfc0408c3'::uuid, 'La diarrhée peut irriter la muqueuse intestinale, ce pansement aide à la protéger et à adsorber les substances indésirables.'), ('f402c007-aa65-48d8-954d-1f0392563a10'::uuid, 'L''inflammation est souvent la cause des douleurs articulaires, ce gel agit localement pour réduire l''œdème et apaiser.'), ('2fc5a54d-74d2-45b1-bdd3-2243151af205'::uuid, 'L''inflammation est un facteur clé de la douleur articulaire, le curcuma aide à moduler cette réponse et soulager.'), ('4230a399-75b2-4d82-b5ae-2bd903cafa27'::uuid, 'La douleur articulaire est souvent liée à l''inflammation, l''harpagophytum aide à diminuer celle-ci et les tensions.'), ('b3ba07fb-3e3b-40a8-a6bf-bceeda0e19d8'::uuid, 'La douleur dentaire peut être associée à une inflammation locale, ce gel à l''arnica aide à réduire l''irritation et apaiser.'), ('554f6f55-6446-46ee-99b5-22dba8d041f2'::uuid, 'Une infection bactérienne peut exacerber la douleur dentaire, ce bain de bouche aide à réduire la charge microbienne.'), ('9ea5121f-9cb7-4909-b4e9-f7e93f90f33e'::uuid, 'La douleur légère est due à la stimulation nerveuse, le paracétamol diminue le signal douloureux au niveau central.'), ('3a504469-97cb-4170-bff5-180ed19c9f1f'::uuid, 'Les douleurs légères peuvent être soulagées par la thermothérapie, cette poche module la circulation sanguine locale.'), ('e7d1650a-d974-4c95-8f66-fd3b47460564'::uuid, 'L''inflammation locale peut causer une douleur légère, l''application de froid aide à réduire l''œdème et apaiser.'), ('4b0c5cf0-2e29-416c-b16f-613d31c16972'::uuid, 'Les douleurs modérées sont souvent liées à l''inflammation, l''ibuprofène réduit cette réaction et soulage la douleur.'), ('a868df78-7773-4d78-afbd-fdb08a76edca'::uuid, 'La contracture musculaire peut causer une douleur modérée, la chaleur aide à détendre les fibres musculaires et améliorer la circulation.'), ('2c01ec10-2d96-4ba0-b5f4-4d19638cec5d'::uuid, 'L''inflammation est une cause fréquente de douleur modérée, ce gel agit localement pour réduire l''inflammation articulaire ou musculaire.'), ('85eb28df-cd21-4bc6-9a8d-d9e739ff26ca'::uuid, 'L''inflammation musculaire est une cause de douleur, ce gel local réduit l''inflammation des tissus sans effet généralisé.'), ('668edce0-4e71-459d-bd5f-fbad08314b52'::uuid, 'L''inflammation des muscles est source de douleur, ce gel agit localement pour réduire l''inflammation et apaiser la zone.'), ('7e007ac5-a663-4715-bec6-e8819d079835'::uuid, 'Les tensions musculaires peuvent provoquer de la douleur, la chaleur libérée par ce patch aide à détendre les fibres.'), ('bece5e2a-d292-468d-90ea-908457c1682a'::uuid, 'La douleur neuropathique implique une dérégulation nerveuse, le baume du Tigre par ses agents irritants locaux modifie la perception.'), ('3fa990ad-8d6c-4bf4-af78-116833cc7dee'::uuid, 'L''atteinte nerveuse est la cause de la neuropathie, ce complexe vitaminique B soutient l''intégrité de la gaine de myéline et la fonction nerveuse.'), ('464f4eb1-576c-4b8b-80ae-78f840fb7e09'::uuid, 'La douleur neuropathique résulte d''une hyperexcitabilité nerveuse, la capsaïcine topique aide à désensibiliser les récepteurs à la douleur.'), ('457897b6-4c57-44dd-9998-f02d87ee4545'::uuid, 'L''inflammation articulaire est souvent responsable des douleurs, ce gel local agit pour réduire l''inflammation sans impact systémique.'), ('84720502-aac4-4f80-8b0b-c4b01dde9d36'::uuid, 'L''usure du cartilage provoque des douleurs articulaires, la glucosamine et la chondroïtine aident à maintenir l''intégrité du cartilage.'), ('e2831c10-1ee0-4547-9845-80424fb28468'::uuid, 'Les douleurs articulaires légères sont souvent dues à une inflammation, l''Harpagophytum aide à moduler cette réponse et apaiser.'), ('c454d74f-6362-4864-8a56-04bc00949dfb'::uuid, 'L''inflammation des tissus musculaires cause des douleurs, ce gel y agit localement pour réduire l''inflammation et apaiser.'), ('9542a764-26bb-4df7-8a7b-a862362b94b5'::uuid, 'Les contractures musculaires génèrent de la douleur, la chaleur diffusée par ce patch aide à détendre les fibres musculaires tendues.'), ('19e0f9b9-d26d-4595-b3f3-7a6022505b40'::uuid, 'L''effort peut entraîner des micro-traumatismes musculaires, cette crème de massage aide à décongestionner et améliorer la récupération.'), ('0f78d37f-5409-4284-bdf5-aef9c98ba621'::uuid, 'La dysbiose se caractérise par un déséquilibre de la flore, ces probiotiques multi-souches aident à restaurer l''équilibre microbien intestinal.'), ('645f34ec-4b6d-4dc4-bb1a-53054596ea89'::uuid, 'La dysbiose intestinale est un déséquilibre de la flore, ces probiotiques à haute concentration aident à repeupler l''intestin.'), ('03338064-b3a4-46c8-ac99-b3a4b95ad14c'::uuid, 'Un déséquilibre du microbiote intestinal caractérise la dysbiose, ces fibres prébiotiques aident à nourrir les bonnes bactéries.'), ('cc3eb50e-6b0d-46e3-b39b-6164ba22b055'::uuid, 'L''eczéma est marqué par une barrière cutanée altérée et une déshydratation, cette crème émolliente aide à former un film protecteur.'), ('b85ef71d-9766-4351-b9eb-35abe7c60320'::uuid, 'La peau atopique a une barrière cutanée déficiente, cette crème émolliente aide à restaurer la fonction de barrière pour hydrater.'), ('4af13863-f070-469b-aa69-16a05db10186'::uuid, 'L''eczéma fragilise la barrière cutanée; une huile lavante surgras sans savon nettoie en douceur, protégeant ainsi l''hydratation de la peau.'), ('947458b2-cc5b-461c-b32f-38c8c61e7627'::uuid, 'L''eczéma altère la fonction de barrière cutanée; une crème émolliente relipidante aide à restaurer cette barrière, diminuant ainsi les poussées d''inflammation.'), ('7cf4ffda-0a64-4eb7-9ab2-c5e2d72ea068'::uuid, 'La peau atopique est souvent déshydratée et irritée; une huile de bain émolliente forme un film protecteur, prévenant ainsi la sécheresse cutanée.') ) AS sub(id, phrase) WHERE produits_complementaires.id = sub.id;